-- ============================================
-- Legislacao full-site: ratinho-junior / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/141403
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = ratinho-junior-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 67
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=141403, tipo Deputado(a), ordemAssinatura=1.
-- 33 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo; valida baseline read-only de 11 rows.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ratinho-junior';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ratinho-junior: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl = 0 THEN
    RAISE NOTICE 'ratinho-junior: baseline projetos_lei ausente neste banco local/CI minimo; coverage Camara sera no-op';
    RETURN;
  END IF;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao ratinho-junior: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('618269', '552152', '544199', '535568', '535518', '530729', '530723', '530717', '530707', '529811', '529806', '529799', '528730', '540271', '535547', '530726', '530721', '530715', '529814', '529809', '529802', '529797', '528727', '524802', '548084', '539346', '535536', '530731', '530725', '530720', '530714', '529813', '529808', '529801', '529796', '528721', '524214', '535581', '535523', '530730', '530724', '530719', '530708', '529812', '529807', '529800', '523906', '535557', '530727', '530722', '530716', '530705', '529810', '529804', '529798', '528728', '526690', '612245', '551684', '622522', '620188', '616797', '564124', '622523', '622521', '613218', '551802');
  IF target_present <> 67 THEN
    RAISE EXCEPTION 'Pre-condicao ratinho-junior: esperadas 67 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('618269', '552152', '544199', '535568', '535518', '530729', '530723', '530717', '530707', '529811', '529806', '529799', '528730', '540271', '535547', '530726', '530721', '530715', '529814', '529809', '529802', '529797', '528727', '524802', '548084', '539346', '535536', '530731', '530725', '530720', '530714', '529813', '529808', '529801', '529796', '528721', '524214', '535581', '535523', '530730', '530724', '530719', '530708', '529812', '529807', '529800', '523906', '535557', '530727', '530722', '530716', '530705', '529810', '529804', '529798', '528728', '526690', '612245', '551684', '622522', '620188', '616797', '564124', '622523', '622521', '613218', '551802')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'ratinho-junior-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao ratinho-junior: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 11 THEN
    RAISE EXCEPTION 'Pre-condicao ratinho-junior: baseline LME read-only esperado 11, encontrado %', lme_count;
  END IF;
END $$;

